import psycopg2
from psycopg2 import sql, extensions

def create_conn():
    conn = psycopg2.connect(dbname="yourdatabase", user="yourusername", password="yourpassword", host="localhost", port="5432") 
    return conn

def close_conn(conn):
    if conn is not None:
        conn.close()

def install_extension(ext_name, conn):
    cur = conn.cursor()
    
    try:        
        # execute the command to create an extension  
        cur.execute('CREATE EXTENSION IF NOT EXISTS {}'.format(sql.Identifier(ext_name))) 

        # commit changes in database (because we're making a change)
        conn.commit()   

    except Exception as e:
         print("An error occurred while installing the extension.")
         print(str(e))
     
    finally:      
        if cur is not None:
            # close cursor
            cur.close()  

def main(): 
    
    conn = create_conn()
    ext_name = input("Enter an extension to install: ")
    install_extension(ext_name, conn)
    close_conn(conn)
        
if __name__ == "__main__":
    main()